const mensSoonScript=`<script id="fix-mens-soon-typing">(()=>{const full="MEN'S SOON";let timer=null,index=0;function clear(){if(timer){clearInterval(timer);timer=null}}function active(el){return el&&el.classList.contains("is-visible")&&location.hash.startsWith("#men-")}function start(){const el=document.querySelector(".collection-empty");if(!active(el)){clear();if(el&&el.textContent!==full)el.textContent=full;return}clear();index=0;el.textContent="";timer=setInterval(()=>{if(!active(el)){clear();return}index+=1;el.textContent=full.slice(0,index);if(index>=full.length)clear()},130)}document.addEventListener("DOMContentLoaded",start);window.addEventListener("hashchange",()=>setTimeout(start,80));setTimeout(start,120)})();</script>`;
