const bareBuyInstructorScript='<script id="bare-buy-instructor-intro-script">(()=>{const buyBar=document.querySelector(".mobile-buy-bar");if(buyBar)buyBar.textContent="吏湲?諛붾줈 援щℓ?섍린";const popup=document.querySelector(".instructor-popup");const close=()=>{popup?.classList.remove("is-open");popup?.setAttribute("aria-hidden","true")};const open=()=>{popup?.classList.add("is-open");popup?.setAttribute("aria-hidden","false")};popup?.querySelector(".instructor-close")?.addEventListener("click",close);popup?.addEventListener("click",event=>{if(event.target===popup)close()});popup?.querySelector(".instructor-cta")?.addEventListener("click",()=>{close();if(typeof openPartnerPopup==="function")openPartnerPopup();else document.querySelector(".partner-apply-button")?.click()});function routeKey(){return "bareInstructorPopupShown:"+(location.hash||"home")}function syncBuyBar(){if(!buyBar)return;const panel=document.querySelector(".purchase-panel"),review=document.querySelector(".detail-tabs");const isDetail=document.body.classList.contains("detail-route");let threshold=220;if(panel){const rect=panel.getBoundingClientRect();threshold=scrollY+rect.top+rect.height*.45}const beforeReview=!review||scrollY<scrollY+review.getBoundingClientRect().top-80;const show=isDetail&&scrollY>Math.max(260,threshold)&&beforeReview;buyBar.classList.toggle("is-visible",show)}function syncInstructorPopup(){if(!document.body.classList.contains("detail-route"))return;if(sessionStorage.getItem(routeKey())==="1")return;const detail=document.querySelector(".product-detail");if(!detail)return;const detailTop=scrollY+detail.getBoundingClientRect().top;const detailHeight=Math.max(detail.scrollHeight,innerHeight);const middlePoint=detailTop+detailHeight*.42;const purchase=document.querySelector(".purchase-panel");let purchasePoint=detailTop+innerHeight*.45;if(purchase){const rect=purchase.getBoundingClientRect();purchasePoint=scrollY+rect.top+rect.height*.7}const trigger=Math.max(detailTop+innerHeight*.5,Math.min(middlePoint,purchasePoint+innerHeight*.18));if(scrollY>trigger){sessionStorage.setItem(routeKey(),"1");open()}}addEventListener("scroll",()=>{syncBuyBar();syncInstructorPopup()},{passive:true});addEventListener("resize",()=>{syncBuyBar();syncInstructorPopup()});addEventListener("hashchange",()=>setTimeout(()=>{syncBuyBar();syncInstructorPopup()},160));setTimeout(()=>{syncBuyBar();syncInstructorPopup()},220)})();</script>';
