function socialCompletePage(provider,user,returnUrl){const fallbackName=(String(user.email||'').split('@')[0]||'BARE MEMBER').replace(/[._-]+/g,' ').trim();const rawName=String(user.name||'').trim();const safeName=/^(Kakao User|移댁뭅?ㅼ쑀?|Naver User)$/i.test(rawName)?fallbackName:rawName;const payload=JSON.stringify({provider,name:safeName||fallbackName||'BARE MEMBER',email:user.email||'',id:user.id||'',createdAt:Date.now()}).replace(/</g,'\\u003c');return new Response(`<!doctype html><html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>LOGIN COMPLETE | BARE.</title></head><body><script>localStorage.setItem('bare_social_user',${JSON.stringify(payload)});location.replace(${JSON.stringify(returnUrl)});</script></body></html>`,{headers:{'content-type':'text/html;charset=utf-8','cache-control':'no-cache'}})}
async function startSocialAuth(request,env,provider){const url=new URL(request.url),origin=url.origin,returnUrl=safeReturnUrl(url.searchParams.get('returnUrl'));if(provider==='kakao'){const clientId=env.KAKAO_REST_API_KEY||env.KAKAO_CLIENT_ID;if(!clientId)return socialMessagePage('移댁뭅???ㅺ? ?꾩슂?댁슂','Cloudflare Pages ?섍꼍蹂?섏뿉 KAKAO_REST_API_KEY瑜?異붽??섎㈃ 移댁뭅??濡쒓렇?몄씠 諛붾줈 ?대┰?덈떎.','/member/login.html?returnUrl='+encodeURIComponent(returnUrl));const redirectUri=origin+'/api/auth/kakao/callback';const auth=new URL('https://kauth.kakao.com/oauth/authorize');auth.searchParams.set('response_type','code');auth.searchParams.set('client_id',clientId);auth.searchParams.set('redirect_uri',redirectUri);auth.searchParams.set('state',encodeState({returnUrl}));return redirect(auth.toString())}const clientId=env.NAVER_CLIENT_ID;if(!clientId)return socialMessagePage('?ㅼ씠踰??ㅺ? ?꾩슂?댁슂','Cloudflare Pages ?섍꼍蹂?섏뿉 NAVER_CLIENT_ID? NAVER_CLIENT_SECRET??異붽??섎㈃ ?ㅼ씠踰?濡쒓렇?몄씠 諛붾줈 ?대┰?덈떎.','/member/login.html?returnUrl='+encodeURIComponent(returnUrl));const auth=new URL('https://nid.naver.com/oauth2.0/authorize');auth.searchParams.set('response_type','code');auth.searchParams.set('client_id',clientId);auth.searchParams.set('redirect_uri',origin+'/api/auth/naver/callback');auth.searchParams.set('state',encodeState({returnUrl}));return redirect(auth.toString())}
async function handleSocialCallback(request,env,provider){const url=new URL(request.url),code=url.searchParams.get('code'),state=url.searchParams.get('state'),data=decodeState(state),returnUrl=safeReturnUrl(data.returnUrl);if(!code)return socialMessagePage('濡쒓렇???ㅽ뙣','媛꾪렪 濡쒓렇???뱀씤 肄붾뱶媛 ?놁뒿?덈떎.','/member/login.html?returnUrl='+encodeURIComponent(returnUrl));try{if(provider==='kakao'){const clientId=env.KAKAO_REST_API_KEY||env.KAKAO_CLIENT_ID;if(!clientId)throw new Error('KAKAO_REST_API_KEY媛 ?놁뒿?덈떎.');const body=new URLSearchParams({grant_type:'authorization_code',client_id:clientId,redirect_uri:url.origin+'/api/auth/kakao/callback',code});if(env.KAKAO_CLIENT_SECRET)body.set('client_secret',env.KAKAO_CLIENT_SECRET);const tokenRes=await fetch('https://kauth.kakao.com/oauth/token',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded;charset=utf-8'},body});const token=await tokenRes.json();if(!tokenRes.ok)throw new Error(token.error_description||'移댁뭅???좏겙 諛쒓툒 ?ㅽ뙣');const profileRes=await fetch('https://kapi.kakao.com/v2/user/me',{headers:{Authorization:'Bearer '+token.access_token}});const profile=await profileRes.json();if(!profileRes.ok)throw new Error('移댁뭅???꾨줈??議고쉶 ?ㅽ뙣');const account=profile.kakao_account||{},kakaoProfile=account.profile||{};return socialCompletePage('kakao',{id:String(profile.id||''),email:account.email||'',name:kakaoProfile.nickname||'Kakao User'},returnUrl)}const clientId=env.NAVER_CLIENT_ID,clientSecret=env.NAVER_CLIENT_SECRET;if(!clientId||!clientSecret)throw new Error('NAVER_CLIENT_ID ?먮뒗 NAVER_CLIENT_SECRET???놁뒿?덈떎.');const tokenUrl=new URL('https://nid.naver.com/oauth2.0/token');tokenUrl.searchParams.set('grant_type','authorization_code');tokenUrl.searchParams.set('client_id',clientId);tokenUrl.searchParams.set('client_secret',clientSecret);tokenUrl.searchParams.set('code',code);tokenUrl.searchParams.set('state',state||'');const tokenRes=await fetch(tokenUrl.toString());const token=await tokenRes.json();if(!tokenRes.ok||!token.access_token)throw new Error(token.error_description||'?ㅼ씠踰??좏겙 諛쒓툒 ?ㅽ뙣');const profileRes=await fetch('https://openapi.naver.com/v1/nid/me',{headers:{Authorization:'Bearer '+token.access_token}});const profile=await profileRes.json();if(!profileRes.ok||profile.resultcode!=='00')throw new Error('?ㅼ씠踰??꾨줈??議고쉶 ?ㅽ뙣');const user=profile.response||{};return socialCompletePage('naver',{id:user.id||'',email:user.email||'',name:user.name||user.nickname||'Naver User'},returnUrl)}catch(error){return socialMessagePage('濡쒓렇???ㅽ뙣',error.message||'媛꾪렪 濡쒓렇??泥섎━ 以?臾몄젣媛 ?앷꼈?듬땲??','/member/login.html?returnUrl='+encodeURIComponent(returnUrl))}}
